from collections import defaultdict

graph: dict[str, list[tuple[str, int]]] = defaultdict(list)

def add_edge(u, v, w=1, directed=True):
    graph[u].append((v, w))
    if not directed:
        graph[v].append((u, w))

for u, v, w in [('A','B',4), ('A','C',1), ('C','B',2),
                 ('B','D',3), ('C','D',5), ('D','E',1)]:
    add_edge(u, v, w)

print(dict(graph))

def reachable(graph, src):
    seen, stack = set(), [src]
    while stack:
        n = stack.pop()
        if n in seen: continue
        seen.add(n)
        for nb, _ in graph.get(n, []):
            if nb not in seen:
                stack.append(nb)
    return seen

print(reachable(graph, 'A'))

import heapq

def dijkstra(graph, src):
    dist = {src: 0}
    pq = [(0, src)]
    while pq:
        d, u = heapq.heappop(pq)
        if d > dist.get(u, float('inf')): continue   # stale entry
        for v, w in graph.get(u, []):
            alt = d + w
            if alt < dist.get(v, float('inf')):
                dist[v] = alt
                heapq.heappush(pq, (alt, v))
    return dist

print(dijkstra(graph, 'A'))   # {'A': 0, 'B': 3, 'C': 1, 'D': 6, 'E': 7}
